195	// buildOrchestratorSummary creates a lightweight summary from orchestrator state.
196	func buildOrchestratorSummary(orch *orchestrator.State) *OrchestratorSummary {
197		summary := &OrchestratorSummary{
198			Adapter: orch.Adapter,
199			Running: orch.Running,
200		}
201		for _, wu := range orch.WorkUnits {
202			summary.WorkUnits = append(summary.WorkUnits, WorkUnitSummary{
203				ID:     wu.ID,
204				Type:   wu.Type,
205				Name:   wu.Name,
206				Source: wu.Source,
207				Total:  wu.Total,
208				Done:   wu.Done,
209			})
210		}
211		return summary
212	}
213	
214	// buildWorkerMap creates a sessionID → workerInfo index from orchestrator state.
215	func buildWorkerMap(orch *orchestrator.State) map[string]*workerInfo {
216		m := make(map[string]*workerInfo)
217	
218		for _, ga := range orch.GlobalAgents {
219			if ga.SessionID != "" {
220				m[ga.SessionID] = &workerInfo{
221					Role:        ga.Role,
222					Icon:        ga.Icon,
223					Description: ga.Description,
224				}
225			}
226		}
227	
228		for _, cb := range orch.Codebases {
229			for _, wt := range cb.Worktrees {
230				for _, w := range wt.Workers {
231					if w.SessionID != "" {
232						m[w.SessionID] = &workerInfo{
233							Role:        w.Role,
234							Icon:        w.Icon,
235							Description: w.Description,
236							Rig:         cb.Name,
237							Name:        w.Name,
238							ID:          w.ID,
239						}
240					}
241				}
242			}
243		}
244	
245		return m
246	}
